import React, { useState, useEffect } from 'react';
import './HeroAnimation.css';

const HeroAnimation: React.FC = () => {
  const [currentTextIndex, setCurrentTextIndex] = useState(0);
  const [isVisible, setIsVisible] = useState(false);

  const animatedTexts = [
    "AI Agent Creation Made Simple",
    "Build in Minutes",
    "With Just Prompts",
    "Multi-Lingual Support",
    "That Scales",
    "With 100+ Connectors"
  ];

  useEffect(() => {
    // Trigger initial animation
    const timer = setTimeout(() => setIsVisible(true), 100);
    
    // Cycle through texts
    const interval = setInterval(() => {
      setCurrentTextIndex((prev) => (prev + 1) % animatedTexts.length);
    }, 3000);

    return () => {
      clearTimeout(timer);
      clearInterval(interval);
    };
  }, [animatedTexts.length]);

  return (
    <div className={`hero-container ${isVisible ? 'visible' : ''}`}>
      <div className="hero-content">
        {/* Main animated heading */}
        <div className="main-title-container">
          <h1 className="main-title">
            <span className="title-line">There's a new</span>
            <div className="animated-text-wrapper">
              <span className="animated-text">{animatedTexts[currentTextIndex]}</span>
            </div>
            <span className="title-line">in town.</span>
          </h1>
        </div>

        {/* Subtitle with gradient */}
        <div className="subtitle-container">
          <p className="subtitle">
            I craft premium AI agents for creators, entrepreneurs and startups who want to 
            convert clients, drive serious revenue and stand out in an ever-crowding market.
          </p>
        </div>

        {/* CTA Section */}
        <div className="cta-container">
          <button className="cta-button">
            Let's work together
            <span className="arrow">→</span>
          </button>
        </div>

        {/* Stats Section */}
        <div className="stats-container">
          <div className="stat-item">
            <div className="stat-number">25+</div>
            <div className="stat-label">Delighted Clients</div>
          </div>
          <div className="stat-item">
            <div className="stat-number">100%</div>
            <div className="stat-label">Satisfaction Rate</div>
          </div>
          <div className="stat-item">
            <div className="stat-number">Daily</div>
            <div className="stat-label">Responses</div>
          </div>
          <div className="stat-item">
            <div className="stat-number">∞</div>
            <div className="stat-label">Passion</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HeroAnimation;
